// Generates lib/services-nav-data.js, a lightweight subset of lib/services-data.js
// and lib/cyber-advisory-data.js containing only the fields the global Header
// mega-menu needs (name, icon, short blurb, and subpage labels).
//
// lib/services-data.js carries full page content (~625KB unminified) for every
// service category/subpage and is needed at build time for static generation.
// 'use client' components like Header should import this generated file instead,
// so the full content data file isn't bundled into the client JS shipped on
// every page.
//
// Re-run after editing serviceCategories/cyber-advisory services:
//   node scripts/gen-services-nav-data.js

const fs = require('fs')
const path = require('path')
const { serviceCategories } = require('../lib/services-data')
const { services: cyberServices } = require('../lib/cyber-advisory-data')

const navServiceCategories = {}
for (const [slug, cat] of Object.entries(serviceCategories)) {
  const subpages = {}
  for (const [subSlug, sub] of Object.entries(cat.subpages || {})) {
    subpages[subSlug] = { h1: sub.h1 }
  }
  navServiceCategories[slug] = {
    name: cat.name,
    icon: cat.icon,
    short: cat.short,
    subpages,
  }
}

const navCyberServices = cyberServices.map(({ slug, name }) => ({ slug, name }))

const out = `// AUTO-GENERATED by scripts/gen-services-nav-data.js — do not edit by hand.
// Lightweight nav data for the global Header mega-menu, derived from
// lib/services-data.js and lib/cyber-advisory-data.js. Re-run the script
// after editing those files.

export const navServiceCategories = ${JSON.stringify(navServiceCategories, null, 2)}

export const navCyberServices = ${JSON.stringify(navCyberServices, null, 2)}
`

fs.writeFileSync(path.join(__dirname, '..', 'lib', 'services-nav-data.js'), out)
console.log('Wrote lib/services-nav-data.js')
